function getDocIcon(n) {
  var k = window.DOC_ICON_MAP[n];
  return k && window.ICONS[k] ? window.ICONS[k] : window.ICONS.legal_doc;
}
function getSectionIcon(l) {
  var k = window.SECTION_ICON_MAP[l];
  return k && window.ICONS[k] ? window.ICONS[k] : '';
}

